using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> typeInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned metadata for: {typeInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), typeInfo);
Console.WriteLine($"Serialized with typed metadata: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// 2a. Type that IS resolvable (default reflection resolver handles it)
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? personInfo))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded – type: {personInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> returned false (unexpected)");
}

// 2b. Options with NO resolver → metadata is NOT available
var empty = new JsonSerializerOptions { TypeInfoResolver = null };

if (empty.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missing))
{
    Console.WriteLine($"TryGetTypeInfo<Person> on empty resolver succeeded (unexpected): {missing!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<Person> on resolver-less options returned false – no exception thrown!");
}

public record Person(string Name, int Age);

